import { NextResponse } from 'next/server'
import { getNextArticleForSlot, markAsPublished, PUBLISH_SLOTS, type QueuedArticle } from '@/lib/content-queue'

// Protect cron endpoints with a secret
const CRON_SECRET = process.env.CRON_SECRET || 'maiy-dev-secret'

export async function POST(request: Request) {
  // Verify secret
  const authHeader = request.headers.get('authorization')
  const secret = authHeader?.replace('Bearer ', '')
  if (secret !== CRON_SECRET) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
  }

  const { slot } = await request.json()

  if (!slot || !['noon', 'evening'].includes(slot)) {
    return NextResponse.json({ error: 'Invalid slot. Use "noon" or "evening".' }, { status: 400 })
  }

  const article = getNextArticleForSlot(slot as 'noon' | 'evening')

  if (!article) {
    return NextResponse.json({
      success: false,
      slot,
      message: `No queued article for ${slot} slot`,
      timestamp: new Date().toISOString(),
    })
  }

  // In Phase 1: mark as published (simulated)
  // Phase 2: actually write MDX file + trigger revalidation
  markAsPublished(article.slug)

  // Log for monitoring
  console.log(`[CRON] Published: "${article.title}" (${slot}) at ${new Date().toISOString()}`)

  return NextResponse.json({
    success: true,
    published: article,
    slot,
    timestamp: new Date().toISOString(),
  })
}

export async function GET() {
  // Status endpoint
  const status = PUBLISH_SLOTS.map((s) => {
    const next = getNextArticleForSlot(s.name)
    return {
      slot: s.name,
      label: s.label,
      cronVN: s.cronVN,
      topic: s.topic,
      nextArticle: next ? { slug: next.slug, title: next.title, scheduledDate: next.scheduledDate } : null,
    }
  })

  return NextResponse.json({
    success: true,
    status: 'ok',
    serverTime: new Date().toISOString(),
    timezone: 'UTC+7',
    slots: status,
  })
}

